import{_ as i,p as e,q as l,a1 as t}from"./framework-e0dd9823.js";const r={},o=t('<h1 id="四个基本时态" tabindex="-1"><a class="header-anchor" href="#四个基本时态" aria-hidden="true">#</a> 四个基本时态</h1><h2 id="一般现在时态" tabindex="-1"><a class="header-anchor" href="#一般现在时态" aria-hidden="true">#</a> 一般现在时态</h2><p>用法：</p><ol><li>表示经常性，习惯性，有规律性的动作或状态。</li><li>表示真理性，客观性的动作或状态。</li><li>不轻易改变的状态。</li><li>此时此刻的状态。</li></ol><p>句型：</p><ol><li>主语 + be + 表语</li><li>主语 + 谓语 + 宾语</li></ol><h2 id="一般过去时态" tabindex="-1"><a class="header-anchor" href="#一般过去时态" aria-hidden="true">#</a> 一般过去时态</h2><p>用法：</p><ol><li>表示过去发生的动作或状态。</li><li>故事，新闻，小说等。</li></ol><p>句型：</p><ol><li>主语 + be（过去式） + 表语</li><li>主语 + 谓语（过去式） + 宾语</li></ol><h2 id="一般将来时态" tabindex="-1"><a class="header-anchor" href="#一般将来时态" aria-hidden="true">#</a> 一般将来时态</h2><p>用法：</p><ol><li>表示将来要发生的动作或状态。</li></ol><p>句型：</p><ol><li>主语 + will + be + 表语</li><li>主语 + will + 谓语 + 宾语</li><li>主语 + be going to + 表语</li><li>主语 + be going to + 谓语 + 宾语</li></ol><h2 id="现在进行时态" tabindex="-1"><a class="header-anchor" href="#现在进行时态" aria-hidden="true">#</a> 现在进行时态</h2><p>用法：</p><ol><li>表示主语此时此刻正在进行的动作。</li></ol><p>句型：</p><ol><li>主语 + 助动词 + 动词现在分词 + 宾语</li></ol><h2 id="特殊主系表句型的构成方式" tabindex="-1"><a class="header-anchor" href="#特殊主系表句型的构成方式" aria-hidden="true">#</a> 特殊主系表句型的构成方式</h2><p>系动词除了 be，还有一些特殊的系动词，这些系动词是在实义动词里面借过来的。充当系动词的作用。如果一个动词充当系动词的作用，那么他的意思也会发生相应的变化。</p><p>这些特殊系动词跟形容词构成系表结构，却是一个状态型谓语，变化规则要遵循状态型的变化规则。</p><p>例句：get</p><p>主系表：</p><ul><li>I get tired every night.</li><li>I don&#39;t get tired every night.</li><li>Do you get tired every night?</li></ul><p>单三：</p><ul><li>She gets tired every night.</li><li>She doesn&#39;t get tired every night.</li><li>Does she get tired every night?</li></ul><p>一般过去时态：</p><ul><li>I got tired last night.</li><li>I didn&#39;t get tired last night.</li><li>Did you get tired last night?</li></ul><p>一般将来时态：</p><ul><li>I will get tired tomorrow.</li><li>I won&#39;t get tired tomorrow.</li><li>Will you get tired tomorrow?</li><li>I am going to get tired tomorrow.</li><li>I am not going to get tired tomorrow.</li><li>Are you going to get tired tomorrow.</li></ul><p>现在进行时态：</p><ul><li>I am getting tired.</li><li>I am not getting tired.</li><li>Are you getting tired?</li></ul>',35),a=[o];function d(n,h){return e(),l("div",null,a)}const s=i(r,[["render",d],["__file","base-tenses.html.vue"]]);export{s as default};
